fn sqrt(x: i32) -> i32 {
    (0..=2000).find(|y| y * y >= x).unwrap()
}

fn main() -> Result<(), io::Error> {
    let (stdin, stdout) = (io::stdin(), io::stdout());
    let mut scan = UnsafeScanner::new(stdin.lock());
    let mut out = BufWriter::new(stdout.lock());

    let mut rev = false;

    let (mut x, mut y) = scan.pair::<i32>();
    if x < 0 {
        rev = !rev;
        x = -x;
    }
    if y < 0 {
        rev = !rev;
        y = -y;
    }

    let dsq = x*x + y*y;

    let d = sqrt(dsq);

    if d * d == dsq {
        return answer!(out, "black");
    }

    answer!(out, match (d & 1 == 1) != rev {
        true => "black",
        false => "white",
    })?;

    Ok(())
